// Colors below were migrated from saved paint into code via api.paint.*
// (the model is now self-colouring; see /ai/colors.md). Edit colours here.
const __pwModel = (() => {
// Toadstool Mushroom — a storybook red cap with white spots on a cream stem.
// Parametric (api.params) + colorable (api.label) for Partwright's Customizer.
const { Manifold, CrossSection } = api;

const p = api.params({
  capRadius: { type: 'number', default: 26, min: 10, max: 60, step: 1, unit: 'mm', label: 'Cap radius' },
  capHeight: { type: 'number', default: 22, min: 8, max: 50, step: 1, unit: 'mm', label: 'Cap height' },
  stemHeight: { type: 'number', default: 30, min: 10, max: 70, step: 1, unit: 'mm', label: 'Stem height' },
  stemRadius: { type: 'number', default: 11, min: 5, max: 30, step: 0.5, unit: 'mm', label: 'Stem radius' },
  spotCount: { type: 'int', default: 9, min: 0, max: 24, label: 'Spot count' },
  spotSize: { type: 'number', default: 4.2, min: 1, max: 9, step: 0.1, unit: 'mm', label: 'Spot size' },
  spotRing: { type: 'number', default: 0.62, min: 0.25, max: 0.9, step: 0.01, label: 'Spot height (0=rim,1=top)' },
  flareRim: { type: 'boolean', default: true, label: 'Flared cap rim' },
});

// ----- Cap profile (revolved around the Z axis) -------------------------------
// Profile X = radial distance, Y = height. The cap is a dome: a flat-ish top
// that curves down to a (optionally flared) rim. We sample a cosine dome so the
// silhouette is the soft storybook bell rather than a bare hemisphere.
const R = p.capRadius;
const H = p.capHeight;
const SEG = 48; // profile sampling resolution
const pts = [];
pts.push([0, 0]); // start on the axis at the rim height
// Outer rim: optionally flare the very bottom edge outward + down a touch so the
// cap overhangs the stem like a real Amanita.
const rimFlare = p.flareRim ? 0.10 * R : 0;
const rimDrop = p.flareRim ? 0.12 * H : 0;
pts.push([R + rimFlare, -rimDrop]); // outermost rim point (slightly below 0)
// Dome curve from rim up to the apex.
for (let i = 1; i <= SEG; i++) {
  const t = i / SEG; // 0 at rim -> 1 at apex
  const radial = R * Math.cos((Math.PI / 2) * t); // R -> 0
  const height = H * Math.sin((Math.PI / 2) * t); // 0 -> H
  pts.push([radial, height]);
}
const capProfile = CrossSection.ofPolygons([pts]);
// Cap solid; its rim sits near z=0, apex near z=H. Lift so the rim slightly
// overlaps the stem top later.
let cap = capProfile.revolve();
cap = api.label(cap, 'cap');

// ----- Spot geometry: scattered Amanita spots on the cap's upper surface -----
// api.scatter samples the cap's own surface + normal at each candidate anchor
// and instances a flattened cream disc there, oriented to the local normal
// (alignToNormal). The `where` predicate keeps spots on the dome's UPPER
// surface only — it rejects the underside "gills" cone (downward-facing
// normals) and the very rim edge (low z) — so spots can only ever land on the
// cap, never on the stem/base/gills (the stem isn't even part of the scatter
// target). minSpacing keeps discs from touching/merging into a blob; the
// small negative offset sinks each disc in just enough to guarantee a solid
// (>=0.5 unit) volumetric overlap with the cap so the union fuses cleanly.
let spots = null;
if (p.spotCount > 0 && p.spotSize > 0) {
  const sr = p.spotSize;
  const spotInstance = Manifold.sphere(sr).scale([1, 1, 0.42]); // flattened dome-hugging disc, "up" = +Z
  spots = api.scatter(cap, spotInstance, {
    count: Math.round(p.spotCount * 1.8), // where()/minSpacing reject some candidates — overshoot the target density
    seed: 7,
    alignToNormal: true,               // disc's +Z follows the dome's surface normal
    offset: -0.6,                      // sink in slightly so it fuses (>=0.5 overlap) without looking recessed
    minSpacing: sr * 2.4,              // keep discs distinct, never merging
    // Upper dome only: skip the underside cone (downward normals) + rim edge.
    // spotRing still drives "how far down toward the rim spots may go" (0=rim, 1=top).
    where: (pt, n) => n[2] > 0.35 && pt[2] > Math.max(0.05, p.spotRing * 0.5) * H,
  });
  spots = api.label(spots, 'spots');
}

// ----- Stem: rounded cream column with a gentle bulge ------------------------
// Revolve a profile: a column that bulges slightly in the middle and rounds in
// at the very top (where it meets the cap) and slightly at the foot.
const sH = p.stemHeight;
const sR = p.stemRadius;
const sPts = [];
const SSEG = 40;
sPts.push([0, 0]);
// rounded foot
sPts.push([sR * 0.72, 0]);
sPts.push([sR * 0.96, sH * 0.06]);
for (let i = 0; i <= SSEG; i++) {
  const t = i / SSEG; // 0 foot -> 1 top
  // subtle barrel bulge: widest ~40% up, narrowing toward the top
  const bulge = 1 + 0.10 * Math.sin(Math.PI * Math.min(t / 0.85, 1));
  const taper = 1 - 0.18 * t; // narrow toward the cap
  const radial = sR * 0.96 * bulge * taper;
  const height = sH * (0.06 + 0.94 * t);
  sPts.push([radial, height]);
}
// round the top edge in
sPts.push([sR * 0.55, sH]);
sPts.push([0, sH]);
let stem = CrossSection.ofPolygons([sPts]).revolve();
stem = api.label(stem, 'stem');

// ----- Assemble: stem at the bottom, cap seated on top (overlapping) ----------
// Place the cap so its rim overlaps the stem top by a solid margin. placeOn with
// a negative gap overlaps volumetrically (>=0.5) so the union is one piece.
const capOnStem = api.placeOn(cap, stem, { gap: -Math.max(1.5, 0.18 * H) });

const parts = [stem, capOnStem];
if (spots) {
  // The spots were built in cap-local coordinates (rim near z=0). Move them by
  // the same offset placeOn applied to the cap so they land on the seated cap.
  const capMinBefore = api.bbox(cap).min[2];
  const capMinAfter = api.bbox(capOnStem).min[2];
  const dz = capMinAfter - capMinBefore;
  parts.push(spots.translate([0, 0, dz]));
}

// One connected mushroom: expect a single component.
return api.expectUnion(parts, { expectComponents: 1 });
})();
api.paint.label("cap", [0.8470588235294118, 0.14901960784313725, 0.17254901960784313]);
api.paint.label("spots", [1, 0.9921568627450981, 0.9607843137254902]);
api.paint.label("stem", [0.9490196078431372, 0.8901960784313725, 0.7764705882352941]);
return __pwModel;
